    0.625842801	0.626042591	0.626186013	0.62627119	0.6263]; %G/cm


adiabatic_pulse_freq=(adiabatic_pulse_fm/(abs(max(adiabatic_pulse_fm))))*sweep_width/2;  % normsalize to +/-1 and then multiply to sweep width

adiabatic_pulse_phase=zeros(size(adiabatic_pulse_freq));
adiabatic_pulse_phase(1)=sweep_duration/length(adiabatic_pulse_freq)*0.5*adiabatic_pulse_freq(1)*360;
for ii=2:length(adiabatic_pulse_fm)
    adiabatic_pulse_phase(ii)=adiabatic_pulse_phase(ii-1)+sweep_duration/length(adiabatic_pulse_freq)*0.5*(adiabatic_pulse_freq(ii)+adiabatic_pulse_freq(ii-1))*360;
end
%figure(1),plot(adiabatic_pulse_phase(:,1:(end-0)))

%create FID-A compatible RF_waveform
aa=0;
Sweep.waveform(:,1)=adiabatic_pulse_phase(:,1:(end-aa));
Sweep.waveform(:,2)=[adiabatic_pulse_am(:,1:(end-aa))];
Sweep.waveform(:,3)=ones(size(adiabatic_pulse_am(:,1:(end-aa))));
Sweep.waveform(:,4)=G.';
Sweep.type  = 'inv';
Sweep.refTp = sweep_duration;
Sweep.bw = sweep_width;
Sweep.B1 = B1;
Sweep.tw1   = tw1;
Sweep.tbw   = tbw;
Sweep.isGM = 1;
Sweep.tthk = 3*(sweep_duration); % GOIA pulse gradient waveform generated assuming 3cm voxel

Gx=(Sweep.tthk/(sweep_duration*1000/1000))/thkX; %scnh
if Sweep.isGM
    %Scale the GM waveform by the factor Gx and then set Gx equal to zero:
    Sweep=rf_scaleGrad(Sweep,Gx);
    Gx=0;
end

save('Philips_GOIA_WURST_625pts.mat','Sweep');

[mv,sc]=rf_blochSim(Sweep,sweep_duration*1000,10,0,sweep_amplitude/1000),title('15.0 uT,8 kHz,4.5 ms 625pts');

% resample
Sweep2 = rf_resample(Sweep,100);
Gnew = gr_resample_SH(G,100);
%a=8;
%Psh1 = polyfit(1:a,linspace(0.6263,Gnew(a),a),2); % correct the tail of the gradient
%f1 = polyval(Psh1,[1:a]);
%Gnew = [f1 Gnew(a:end-a-1) flip(f1)];
%Sweep2.waveform(:,4) = circshift(Gnew,-0);

Gx=(Sweep2.tthk/(sweep_duration*1000/1000))/thkX; %scnh
if Sweep2.isGM
    %Scale the GM waveform by the factor Gx and then set Gx equal to zero:
    Sweep2=rf_scaleGrad(Sweep2,Gx);
    Gx=0;
end

save('Philips_GOIA_WURST_100pts.mat','Sweep2');

[mv2,sc2]=rf_blochSim(Sweep2,sweep_duration*1000,10,0,sweep_amplitude/1000),title('15.0 uT,8 kHz,4.5 ms 100pts');

% figure(1),plot(G);
% hold on
% plot([1:100]+312,Gnew);
% hold off

% To compare GOIA before and after resample
figure(100),plot(sc,mv(3,:),'r',sc2,mv2(3,:),'b'),legend('GOIA 625 pts', 'GOIA 100 pts')

%% Start of resample function

function Gr_out=gr_resample_SH(Gr_in,N);
% Adapted from Jamie Near, McGill University 2014 -- SH and MGSaleh 2019
%
% USAGE:
% Gr_out=gr_resample(RF_in,N);
%
% DESCRIPTION:
% Resample the input Gr waveform pulse into a new waveform with N discrete points.
%
% INPUTS:
% Gr_in     = Input GR waveform
% N         = Number of points in new Gr waveform
%
% OUTPUTS:
% Gr_out    = Output GR waveform following resampling.

P=N;
Q=length(Gr_in);

Gr_out=Gr_in;
newGradient=resample(Gr_out,P,Q);
Gr_out=newGradient;


end
